module pe(
    input clk,
    input rst,
    input [31:0] a,
    input [31:0] b,
    output [31:0] c
);
    reg [31:0] accum;

    always @(posedge clk) begin
        if (rst) begin
            accum <= 0;
        end else begin
            accum <= accum + (a * b);
        end
    end

    assign c = accum;
endmodule
